11	// maxReviewerEventBody is the hard cap on bytes written to an event body for
12	// a reviewer verdict event. Full streams persist as a sidecar artifact; the
13	// body holds a summary plus the artifact path. 512 bytes fits a verdict name,
14	// one line of rationale, and a path without blowing the bead event envelope
15	// or tipping us toward bd's 65,535-byte per-field cap.
16	const maxReviewerEventBody = 512
17	
18	// persistReviewerStream writes the full reviewer raw output to an artifact
19	// sidecar under the project's execution evidence tree. Returns the relative
20	// path (from projectRoot) on success, empty string plus error on failure.
21	//
22	// The sidecar path shape is
23	// `.ddx/executions/<attemptID>/reviewer-stream.log` when attemptID is
24	// available; otherwise a timestamped fallback under
25	// `.ddx/executions/reviewer-streams/` keeps streams grouped even without a
26	// corresponding bundle. The caller is responsible for not losing the stream
27	// when this returns a non-nil error — log but do not drop the verdict.
28	func persistReviewerStream(projectRoot, beadID, attemptID, fullStream string) (string, error) {
29		if projectRoot == "" {
30			return "", fmt.Errorf("reviewer stream artifact: empty projectRoot")
31		}
32		if fullStream == "" {
33			return "", nil
34		}
35	
36		var dir, filename string
37		if attemptID != "" {
38			dir = filepath.Join(projectRoot, ".ddx", "executions", attemptID)
39			filename = "reviewer-stream.log"
40		} else {
41			dir = filepath.Join(projectRoot, ".ddx", "executions", "reviewer-streams")
42			ts := time.Now().UTC().Format("20060102T150405")
43			bid := beadID
44			if bid == "" {
45				bid = "unknown"
46			}
47			filename = ts + "-" + bid + ".log"
48		}
49	
50		if err := os.MkdirAll(dir, 0o755); err != nil {
51			return "", fmt.Errorf("reviewer stream artifact: mkdir %s: %w", dir, err)
52		}
53		path := filepath.Join(dir, filename)
54		if err := os.WriteFile(path, []byte(fullStream), 0o644); err != nil {
55			return "", fmt.Errorf("reviewer stream artifact: write %s: %w", path, err)
56		}
57	
58		rel, err := filepath.Rel(projectRoot, path)
59		if err != nil {
60			// Not fatal — return the absolute path so the reference still works.
61			return path, nil
62		}
63		return rel, nil
64	}
