66	// reviewEventBody assembles a bounded event body for a reviewer verdict event
67	// from the verdict label, the rationale (which may be a full review stream),
68	// and the artifact path where the full stream was persisted. Guarantees the
69	// returned string is at most maxReviewerEventBody bytes.
70	//
71	// Layout:
72	//
73	//	<verdict>
74	//	<first non-empty rationale line, truncated to fit>
75	//	artifact: <artifactPath>
76	//
77	// artifactPath is optional; when absent the layout omits that line.
78	func reviewEventBody(verdict, rationale, artifactPath string) string {
79		verdict = strings.TrimSpace(verdict)
80		rationale = strings.TrimSpace(rationale)
81		artifactPath = strings.TrimSpace(artifactPath)
82	
83		var firstLine string
84		if rationale != "" {
85			for _, line := range strings.Split(rationale, "\n") {
86				trimmed := strings.TrimSpace(line)
87				if trimmed != "" {
88					firstLine = trimmed
89					break
90				}
91			}
92		}
93	
94		var b strings.Builder
95		if verdict != "" {
96			b.WriteString(verdict)
97		}
98	
99		artifactLine := ""
100		if artifactPath != "" {
101			artifactLine = "artifact: " + artifactPath
102		}
103	
104		// Reserve room for the verdict and the artifact line plus two newlines.
105		reserved := b.Len()
106		if artifactLine != "" {
107			reserved += len("\n") + len(artifactLine)
108		}
109		budget := maxReviewerEventBody - reserved
110		// Account for the newline before the rationale line.
111		if firstLine != "" {
112			budget -= len("\n")
113		}
114		if budget < 0 {
115			budget = 0
116		}
117	
118		if firstLine != "" {
119			if len(firstLine) > budget {
120				// Leave space for a trailing truncation marker.
121				const marker = "…"
122				if budget > len(marker) {
123					firstLine = firstLine[:budget-len(marker)] + marker
124				} else {
125					firstLine = firstLine[:budget]
126				}
127			}
128			if firstLine != "" {
129				b.WriteString("\n")
130				b.WriteString(firstLine)
131			}
132		}
133	
134		if artifactLine != "" {
135			b.WriteString("\n")
136			b.WriteString(artifactLine)
137		}
138	
139		out := b.String()
140		if len(out) > maxReviewerEventBody {
141			out = out[:maxReviewerEventBody]
142		}
143		return out
144	}
