15	// Stable refusal codes returned when a review turn cannot proceed. These are
16	// part of the external contract — operators triage on these literal strings.
17	const (
18		RefusalCodePromptBudgetExceeded = "PROMPT_BUDGET_EXCEEDED"
19		RefusalCodeCostCapExceeded      = "COST_CAP_EXCEEDED"
20		RefusalCodeReviewerUnavailable  = "REVIEWER_UNAVAILABLE"
21	)
22	
23	// ReviewRefusalBody is the structured JSON body attached to all review turn
24	// refusals. Code is one of the RefusalCode* constants above.
25	type ReviewRefusalBody struct {
26		Code           string `json:"code"`
27		Message        string `json:"message"`
28		Retryable      bool   `json:"retryable"`
29		OperatorAction string `json:"operator_action"`
30	}
31	
32	// MarshalRefusalJSON returns the JSON encoding of a ReviewRefusalBody.
33	func MarshalRefusalJSON(code, message, operatorAction string, retryable bool) (string, error) {
34		b := ReviewRefusalBody{
35			Code:           code,
36			Message:        message,
37			Retryable:      retryable,
38			OperatorAction: operatorAction,
39		}
40		data, err := json.Marshal(b)
41		if err != nil {
42			return "", err
43		}
44		return string(data), nil
45	}
