47	// ReviewCostCapExceededError is returned by AppendTurn when adding the turn's
48	// cost to the session's accumulated cost would exceed MaxBillableUSD.
49	type ReviewCostCapExceededError struct {
50		SessionID   string
51		CurrentCost float64
52		TurnCost    float64
53		MaxUSD      float64
54	}
55	
56	func (e *ReviewCostCapExceededError) Error() string {
57		return fmt.Sprintf(
58			"COST_CAP_EXCEEDED: session %s current cost $%.4f + turn cost $%.4f exceeds max_billable_usd $%.4f",
59			e.SessionID, e.CurrentCost, e.TurnCost, e.MaxUSD,
60		)
61	}
62	
63	// RefusalBody returns the structured JSON refusal body for this error.
64	func (e *ReviewCostCapExceededError) RefusalBody() ReviewRefusalBody {
65		return ReviewRefusalBody{
66			Code:           RefusalCodeCostCapExceeded,
67			Message:        e.Error(),
68			Retryable:      false,
69			OperatorAction: "raise max_billable_usd for the review session or create a new session",
70		}
71	}
72	
73	// ReviewerUnavailableError is returned when a review turn is attempted on a
74	// session that is in a terminal state and cannot accept new reviewer turns.
75	type ReviewerUnavailableError struct {
76		SessionID string
77		Status    string
78	}
79	
80	func (e *ReviewerUnavailableError) Error() string {
81		return fmt.Sprintf(
82			"REVIEWER_UNAVAILABLE: session %s has status %q and cannot accept new review turns",
83			e.SessionID, e.Status,
84		)
85	}
86	
87	// RefusalBody returns the structured JSON refusal body for this error.
88	func (e *ReviewerUnavailableError) RefusalBody() ReviewRefusalBody {
89		return ReviewRefusalBody{
90			Code:           RefusalCodeReviewerUnavailable,
91			Message:        e.Error(),
92			Retryable:      false,
93			OperatorAction: "open a new review session to continue",
94		}
95	}
