104	// ReviewSession is the server-side review state machine persisted under
105	// .ddx/reviews/<session-id>/ for Story 16 and review mutations.
106	//
107	// Story 16 on-disk contract:
108	//   - manifest.json stores the session metadata only: id, artifact refs,
109	//     rubric/template/prompt refs, status, and billing limits.
110	//   - turns.jsonl is append-only JSONL. Each non-empty line is one ReviewTurn
111	//     record with actor, content, cost_usd, and created_at.
112	//   - attachments/ stores any binary sidecar files for the session.
113	//
114	// The manifest is written when a session is created. Turns are appended
115	// without rewriting prior lines so the review transcript remains durable and
116	// streamable.
117	type ReviewSession struct {
118		ID             string       `json:"id"`
119		ArtifactID     string       `json:"artifact_id"`
120		ArtifactSHA    string       `json:"artifact_sha"`
121		ArtifactGitRev string       `json:"artifact_git_rev"`
122		SystemRubric   string       `json:"system_rubric"`
123		TemplateRef    string       `json:"template_ref"`
124		PromptRef      string       `json:"prompt_ref"`
125		Status         string       `json:"status"`
126		Turns          []ReviewTurn `json:"turns,omitempty"`
127		CostUSD        float64      `json:"cost_usd"`
128		MaxBillableUSD float64      `json:"max_billable_usd"`
129	}
130	
131	// ReviewTurn is one append-only transcript entry in turns.jsonl.
132	type ReviewTurn struct {
133		Actor     string    `json:"actor"`
134		Content   string    `json:"content"`
135		CostUSD   float64   `json:"cost_usd"`
136		CreatedAt time.Time `json:"created_at"`
137	}
