139	type reviewSessionManifest struct {
140		ID             string  `json:"id"`
141		ArtifactID     string  `json:"artifact_id"`
142		ArtifactSHA    string  `json:"artifact_sha"`
143		ArtifactGitRev string  `json:"artifact_git_rev"`
144		SystemRubric   string  `json:"system_rubric"`
145		TemplateRef    string  `json:"template_ref"`
146		PromptRef      string  `json:"prompt_ref"`
147		Status         string  `json:"status"`
148		CostUSD        float64 `json:"cost_usd"`
149		MaxBillableUSD float64 `json:"max_billable_usd"`
150	}
