152	// ReviewSessionStore persists review sessions under .ddx/reviews/.
153	type ReviewSessionStore struct {
154		projectRoot string
155		mu          sync.Mutex
156	}
157	
158	// NewReviewSessionStore constructs a store rooted at projectRoot.
159	func NewReviewSessionStore(projectRoot string) *ReviewSessionStore {
160		return &ReviewSessionStore{projectRoot: projectRoot}
161	}
162	
163	// Create initializes the session directory, writes manifest.json, seeds
164	// turns.jsonl, and creates attachments/.
165	func (s *ReviewSessionStore) Create(session ReviewSession) error {
166		if s == nil {
167			return errors.New("review session store: nil store")
168		}
169		root, err := s.sessionRoot(session.ID)
170		if err != nil {
171			return err
172		}
173	
174		s.mu.Lock()
175		defer s.mu.Unlock()
176	
177		if err := os.MkdirAll(filepath.Join(root, reviewAttachmentsDir), 0o755); err != nil {
178			return fmt.Errorf("review session: mkdir attachments: %w", err)
179		}
180		if err := writeJSONFile(filepath.Join(root, reviewManifestName), reviewSessionManifestFrom(session)); err != nil {
181			return err
182		}
183		if err := os.WriteFile(filepath.Join(root, reviewTurnsName), nil, 0o644); err != nil {
184			return fmt.Errorf("review session: seed turns: %w", err)
185		}
186		return nil
187	}
