189	// AppendTurn appends a single transcript entry to turns.jsonl. It enforces
190	// MaxBillableUSD: if the session has a non-zero budget cap and the accumulated
191	// cost plus this turn's cost would exceed it, AppendTurn returns a
192	// *ReviewCostCapExceededError without writing the turn. On success the
193	// manifest's CostUSD accumulator is updated to reflect the new total.
194	func (s *ReviewSessionStore) AppendTurn(sessionID string, turn ReviewTurn) error {
195		if s == nil {
196			return errors.New("review session store: nil store")
197		}
198		root, err := s.sessionRoot(sessionID)
199		if err != nil {
200			return err
201		}
202	
203		s.mu.Lock()
204		defer s.mu.Unlock()
205	
206		if err := os.MkdirAll(root, 0o755); err != nil {
207			return fmt.Errorf("review session: mkdir session: %w", err)
208		}
209	
210		// Load the manifest to check the cost cap and read the current accumulated
211		// cost. If the manifest does not exist yet (session created without Create),
212		// proceed without enforcement.
213		manifestPath := filepath.Join(root, reviewManifestName)
214		var manifest *reviewSessionManifest
215		if data, readErr := os.ReadFile(manifestPath); readErr == nil {
216			var m reviewSessionManifest
217			if jsonErr := json.Unmarshal(data, &m); jsonErr == nil {
218				manifest = &m
219			}
220		}
221	
222		if manifest != nil && manifest.MaxBillableUSD > 0 {
223			if manifest.CostUSD+turn.CostUSD > manifest.MaxBillableUSD {
224				return &ReviewCostCapExceededError{
225					SessionID:   sessionID,
226					CurrentCost: manifest.CostUSD,
227					TurnCost:    turn.CostUSD,
228					MaxUSD:      manifest.MaxBillableUSD,
229				}
230			}
231		}
232	
233		if turn.CreatedAt.IsZero() {
234			turn.CreatedAt = time.Now().UTC()
235		}
236		path := filepath.Join(root, reviewTurnsName)
237		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
238		if err != nil {
239			return fmt.Errorf("review session: open turns: %w", err)
240		}
241		defer f.Close()
242		if err := json.NewEncoder(f).Encode(turn); err != nil {
243			return fmt.Errorf("review session: encode turn: %w", err)
244		}
245	
246		// Update the manifest's CostUSD accumulator so the next AppendTurn sees
247		// the correct running total.
248		if manifest != nil {
249			manifest.CostUSD += turn.CostUSD
250			_ = writeJSONFile(manifestPath, *manifest)
251		}
252	
253		return nil
254	}
255	
256	// Load reads the manifest plus append-only transcript back into memory.
257	func (s *ReviewSessionStore) Load(sessionID string) (*ReviewSession, error) {
258		if s == nil {
259			return nil, errors.New("review session store: nil store")
260		}
261		root, err := s.sessionRoot(sessionID)
262		if err != nil {
263			return nil, err
264		}
265	
266		data, err := os.ReadFile(filepath.Join(root, reviewManifestName))
267		if err != nil {
268			return nil, fmt.Errorf("review session: read manifest: %w", err)
269		}
270		var manifest reviewSessionManifest
271		if err := json.Unmarshal(data, &manifest); err != nil {
272			return nil, fmt.Errorf("review session: parse manifest: %w", err)
273		}
274		session := &ReviewSession{
275			ID:             manifest.ID,
276			ArtifactID:     manifest.ArtifactID,
277			ArtifactSHA:    manifest.ArtifactSHA,
278			ArtifactGitRev: manifest.ArtifactGitRev,
279			SystemRubric:   manifest.SystemRubric,
280			TemplateRef:    manifest.TemplateRef,
281			PromptRef:      manifest.PromptRef,
282			Status:         manifest.Status,
283			CostUSD:        manifest.CostUSD,
284			MaxBillableUSD: manifest.MaxBillableUSD,
285		}
286	
287		turnsPath := filepath.Join(root, reviewTurnsName)
288		f, err := os.Open(turnsPath)
289		if err != nil {
290			if os.IsNotExist(err) {
291				return session, nil
292			}
293			return nil, fmt.Errorf("review session: read turns: %w", err)
294		}
295		defer f.Close()
296	
297		scanner := bufio.NewScanner(f)
298		scanner.Buffer(make([]byte, 0, 64*1024), 8*1024*1024)
299		for scanner.Scan() {
300			line := strings.TrimSpace(scanner.Text())
301			if line == "" {
302				continue
303			}
304			var turn ReviewTurn
305			if err := json.Unmarshal([]byte(line), &turn); err != nil {
306				return nil, fmt.Errorf("review session: parse turn: %w", err)
307			}
308			session.Turns = append(session.Turns, turn)
309		}
310		if err := scanner.Err(); err != nil {
311			return nil, fmt.Errorf("review session: scan turns: %w", err)
312		}
313		return session, nil
314	}
315	
316	func (s *ReviewSessionStore) sessionRoot(sessionID string) (string, error) {
317		if s == nil {
318			return "", errors.New("review session store: nil store")
319		}
320		if s.projectRoot == "" {
321			return "", errors.New("review session store: empty project root")
322		}
323		if sessionID == "" {
324			return "", errors.New("review session store: empty session id")
325		}
326		if sessionID == "." || sessionID == ".." || strings.ContainsAny(sessionID, "/\\") {
327			return "", fmt.Errorf("review session store: invalid session id %q", sessionID)
328		}
329		return filepath.Join(s.projectRoot, ".ddx", reviewSessionsDirName, sessionID), nil
330	}
331	
332	func reviewSessionManifestFrom(session ReviewSession) reviewSessionManifest {
333		return reviewSessionManifest{
334			ID:             session.ID,
335			ArtifactID:     session.ArtifactID,
336			ArtifactSHA:    session.ArtifactSHA,
337			ArtifactGitRev: session.ArtifactGitRev,
338			SystemRubric:   session.SystemRubric,
339			TemplateRef:    session.TemplateRef,
340			PromptRef:      session.PromptRef,
341			Status:         session.Status,
342			CostUSD:        session.CostUSD,
343			MaxBillableUSD: session.MaxBillableUSD,
344		}
345	}
346	
347	func writeJSONFile(path string, v any) error {
348		data, err := json.MarshalIndent(v, "", "  ")
349		if err != nil {
350			return fmt.Errorf("review session: marshal %s: %w", path, err)
351		}
352		data = append(data, '\n')
353		if err := os.WriteFile(path, data, 0o644); err != nil {
354			return fmt.Errorf("review session: write %s: %w", path, err)
355		}
356		return nil
357	}
