3	import (
4		"fmt"
5		"html"
6		"strings"
7	
8		"github.com/DocumentDrivenDX/ddx/internal/evidence"
9	)
10	
11	// ReviewPromptFinding captures an unresolved finding that should be pinned
12	// to the tail of a review-session prompt.
13	type ReviewPromptFinding struct {
14		Location string
15		Summary  string
16	}
17	
18	// ReviewPromptRenderInput describes the structured evidence envelope used to
19	// render a review-session prompt.
20	type ReviewPromptRenderInput struct {
21		Session ReviewSession
22	
23		FirstUserIntent       string
24		ExplicitUserDecisions []string
25		SessionMemorySummary  string
26		LastVerbatimTurns     int
27		UnresolvedFindings    []ReviewPromptFinding
28		MaxPromptBytes        int
29	}
30	
31	// ReviewPromptRenderResult is the structured output of RenderReviewPrompt.
32	type ReviewPromptRenderResult struct {
33		Prompt   string
34		Overflow bool
35		Sections []evidence.EvidenceAssemblySection
36	}
37	
38	// PromptBudgetExceededError is returned when the pinned floor cannot fit in
39	// the caller's prompt budget.
40	type PromptBudgetExceededError struct {
41		ObservedBytes int
42		CapBytes      int
43	}
44	
45	func (e *PromptBudgetExceededError) Error() string {
46		return fmt.Sprintf(
47			"PROMPT_BUDGET_EXCEEDED: pinned floor observed %d bytes exceeds cap %d bytes",
48			e.ObservedBytes,
49			e.CapBytes,
50		)
51	}
52	
53	// RenderReviewPrompt assembles a structured review-session prompt with
54	// pinned sections first, then rolling session memory, then unresolved
55	// findings.
56	func RenderReviewPrompt(input ReviewPromptRenderInput) (ReviewPromptRenderResult, error) {
57		max := input.MaxPromptBytes
58		if max <= 0 {
59			max = evidence.DefaultMaxPromptBytes
60		}
61	
62		pinned := renderPinnedReviewPrompt(input)
63		if len(pinned) > max {
64			return ReviewPromptRenderResult{}, &PromptBudgetExceededError{
65				ObservedBytes: len(pinned),
66				CapBytes:      max,
67			}
68		}
69	
70		rolling := renderRollingReviewPrompt(input)
71		unresolved := renderUnresolvedFindingsPrompt(input.UnresolvedFindings)
72	
73		assembled := evidence.AssembleInline([]evidence.SectionInput{
74			{
75				Name:     "pinned",
76				Content:  pinned,
77				MinFloor: true,
78			},
79			{
80				Name:    "rolling",
81				Content: rolling,
82			},
83			{
84				Name:    "unresolved-findings",
85				Content: unresolved,
86			},
87		}, max)
88	
89		return ReviewPromptRenderResult{
90			Prompt:   assembled.Prompt,
91			Overflow: assembled.Overflow,
92			Sections: assembled.Sections,
93		}, nil
94	}
95	
96	func renderPinnedReviewPrompt(input ReviewPromptRenderInput) string {
97		session := input.Session
98		var sb strings.Builder
99		sb.WriteString("<pinned>\n")
100	
101		sb.WriteString("  <artifact-identity>\n")
102		fmt.Fprintf(&sb, "    <artifact-id>%s</artifact-id>\n", html.EscapeString(session.ArtifactID))
103		fmt.Fprintf(&sb, "    <artifact-sha>%s</artifact-sha>\n", html.EscapeString(session.ArtifactSHA))
104		fmt.Fprintf(&sb, "    <artifact-git-rev>%s</artifact-git-rev>\n", html.EscapeString(session.ArtifactGitRev))
105		sb.WriteString("  </artifact-identity>\n")
106	
107		sb.WriteString("  <system-rubric>\n")
108		if strings.TrimSpace(session.SystemRubric) == "" {
109			sb.WriteString("    <empty/>\n")
110		} else {
111			sb.WriteString("    ")
112			sb.WriteString(html.EscapeString(strings.TrimSpace(session.SystemRubric)))
113			sb.WriteString("\n")
114		}
115		sb.WriteString("  </system-rubric>\n")
116	
117		sb.WriteString("  <story-17-template-prompt>\n")
118		fmt.Fprintf(&sb, "    <template-ref>%s</template-ref>\n", html.EscapeString(session.TemplateRef))
119		fmt.Fprintf(&sb, "    <prompt-ref>%s</prompt-ref>\n", html.EscapeString(session.PromptRef))
120		sb.WriteString("  </story-17-template-prompt>\n")
121	
122		firstIntent := strings.TrimSpace(input.FirstUserIntent)
123		if firstIntent == "" {
124			firstIntent = firstUserTurnContent(session.Turns)
125		}
126		sb.WriteString("  <first-user-intent>\n")
127		if firstIntent == "" {
128			sb.WriteString("    <empty/>\n")
129		} else {
130			sb.WriteString("    ")
131			sb.WriteString(html.EscapeString(firstIntent))
132			sb.WriteString("\n")
133		}
134		sb.WriteString("  </first-user-intent>\n")
135	
136		decisions := input.ExplicitUserDecisions
137		if len(decisions) == 0 {
138			decisions = explicitUserDecisions(session.Turns)
139		}
140		sb.WriteString("  <explicit-user-decisions>\n")
141		if len(decisions) == 0 {
142			sb.WriteString("    <empty/>\n")
143		} else {
144			for _, decision := range decisions {
145				decision = strings.TrimSpace(decision)
146				if decision == "" {
147					continue
148				}
149				sb.WriteString("    <decision>")
150				sb.WriteString(html.EscapeString(decision))
151				sb.WriteString("</decision>\n")
152			}
153		}
154		sb.WriteString("  </explicit-user-decisions>\n")
155	
156		sb.WriteString("</pinned>\n")
157		return sb.String()
158	}
159	
160	func renderRollingReviewPrompt(input ReviewPromptRenderInput) string {
161		var sb strings.Builder
162		sb.WriteString("<rolling>\n")
163	
164		sb.WriteString("  <session-memory-summary>\n")
165		summary := strings.TrimSpace(input.SessionMemorySummary)
166		if summary == "" {
167			summary = defaultSessionMemorySummary(input.Session)
168		}
169		if summary == "" {
170			sb.WriteString("    <empty/>\n")
171		} else {
172			sb.WriteString("    ")
173			sb.WriteString(html.EscapeString(summary))
174			sb.WriteString("\n")
175		}
176		sb.WriteString("  </session-memory-summary>\n")
177	
178		turns := input.Session.Turns
179		limit := input.LastVerbatimTurns
180		if limit <= 0 || limit > len(turns) {
181			limit = len(turns)
182		}
183		sb.WriteString("  <last-verbatim-turns>\n")
184		if limit == 0 {
185			sb.WriteString("    <empty/>\n")
186		} else {
187			start := len(turns) - limit
188			for _, turn := range turns[start:] {
189				fmt.Fprintf(&sb, "    <turn actor=%q>\n", html.EscapeString(turn.Actor))
190				if strings.TrimSpace(turn.Content) == "" {
191					sb.WriteString("      <empty/>\n")
192				} else {
193					sb.WriteString("      ")
194					sb.WriteString(html.EscapeString(strings.TrimSpace(turn.Content)))
195					sb.WriteString("\n")
196				}
197				sb.WriteString("    </turn>\n")
198			}
199		}
200		sb.WriteString("  </last-verbatim-turns>\n")
201	
202		sb.WriteString("</rolling>\n")
203		return sb.String()
204	}
205	
206	func renderUnresolvedFindingsPrompt(findings []ReviewPromptFinding) string {
207		var sb strings.Builder
208		sb.WriteString("<unresolved-findings>\n")
209		if len(findings) == 0 {
210			sb.WriteString("  <empty/>\n")
211		} else {
212			for _, finding := range findings {
213				sb.WriteString("  <finding>\n")
214				if strings.TrimSpace(finding.Location) != "" {
215					fmt.Fprintf(&sb, "    <location>%s</location>\n", html.EscapeString(strings.TrimSpace(finding.Location)))
216				}
217				if strings.TrimSpace(finding.Summary) != "" {
218					fmt.Fprintf(&sb, "    <summary>%s</summary>\n", html.EscapeString(strings.TrimSpace(finding.Summary)))
219				}
220				sb.WriteString("  </finding>\n")
221			}
222		}
223		sb.WriteString("</unresolved-findings>\n")
224		return sb.String()
225	}
226	
227	func firstUserTurnContent(turns []ReviewTurn) string {
228		for _, turn := range turns {
229			if strings.EqualFold(strings.TrimSpace(turn.Actor), "user") {
230				return strings.TrimSpace(turn.Content)
231			}
232		}
233		return ""
234	}
235	
236	func explicitUserDecisions(turns []ReviewTurn) []string {
237		seenFirst := false
238		decisions := make([]string, 0)
239		for _, turn := range turns {
240			if !strings.EqualFold(strings.TrimSpace(turn.Actor), "user") {
241				continue
242			}
243			if !seenFirst {
244				seenFirst = true
245				continue
246			}
247			content := strings.TrimSpace(turn.Content)
248			if content != "" {
249				decisions = append(decisions, content)
250			}
251		}
252		return decisions
253	}
254	
255	func defaultSessionMemorySummary(session ReviewSession) string {
256		if len(session.Turns) == 0 {
257			return ""
258		}
259		return fmt.Sprintf(
260			"%d turns across session %s (%s)",
261			len(session.Turns),
262			strings.TrimSpace(session.ID),
263			strings.TrimSpace(session.Status),
264		)
265	}
