231	// drainServiceEvents reads service events and returns the final-event payload,
232	// the routing decision (when present in the routing_decision start event), and
233	// any canonical progress payloads emitted by the service.
234	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
235		return drainServiceEventsWithWriter(events, nil)
236	}
237	
238	func drainServiceEventsWithWriter(events <-chan agentlib.ServiceEvent, w io.Writer) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
239		return drainServiceEventsWithRenderer(events, w, NewWorkLogRenderer(WorkLogRendererOptions{WorkPhase: "do"}), nil)
240	}
241	
242	// drainServiceEventsWithRenderer drains the event stream and returns the
243	// aggregated final/routing/progress data. When wd is non-nil it activates
244	// three wedge-prevention mechanisms:
245	//
246	//  1. Meaningful-event idle reset: the idle timer only resets on tool_call,
247	//     tool_result, and final events — not on text_delta/progress/other noise.
248	//  2. Loop detection: identical (call, result) pairs that repeat ≥4 times in
249	//     an 8-entry window trigger wd.cancel.
250	//  3. Per-tool-call timeout: a tool_call without a matching tool_result within
251	//     wd.toolCallTimeout triggers wd.cancel.
252	func drainServiceEventsWithRenderer(events <-chan agentlib.ServiceEvent, w io.Writer, renderer WorkLogRenderer, wd *drainWatchdog) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
253		var final *agentlib.ServiceFinalData
254		var routing *agentlib.ServiceRoutingDecisionData
255		var progress []agentlib.ServiceProgressData
256	
257		// Fast path: no watchdog, simple range loop with no timer overhead.
258		if wd == nil || (wd.idleTimeout == 0 && wd.toolCallTimeout == 0) {
259			for ev := range events {
260				decoded, err := agentlib.DecodeServiceEvent(ev)
261				if err != nil {
262					continue
263				}
264				switch {
265				case decoded.RoutingDecision != nil:
266					routing = decoded.RoutingDecision
267					if w != nil {
268						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
269							_, _ = fmt.Fprint(w, line)
270						}
271					}
272				case decoded.Progress != nil:
273					progress = append(progress, *decoded.Progress)
274					if w != nil {
275						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
276					}
277				case decoded.Final != nil:
278					final = decoded.Final
279				}
280			}
281			return final, routing, progress
282		}
283	
284		// Watchdog path: select loop so timers can fire alongside event reads.
285		ld := &loopDetector{}
286		var pendingCall *agentlib.ServiceToolCallData
287	
288		// resetIdle stops and restarts the idle timer. Only called on meaningful events.
289		var idleTimer *time.Timer
290		var idleTimerC <-chan time.Time
291		resetIdle := func() {
292			if wd.idleTimeout <= 0 {
293				return
294			}
295			if idleTimer == nil {
296				idleTimer = time.NewTimer(wd.idleTimeout)
297				idleTimerC = idleTimer.C
298				return
299			}
300			if !idleTimer.Stop() {
301				select {
302				case <-idleTimer.C:
303				default:
304				}
305			}
306			idleTimer.Reset(wd.idleTimeout)
307		}
308	
309		var toolCallTimer *time.Timer
310		var toolCallTimerC <-chan time.Time
311		startToolCallTimer := func() {
312			if wd.toolCallTimeout <= 0 {
313				return
314			}
315			if toolCallTimer == nil {
316				toolCallTimer = time.NewTimer(wd.toolCallTimeout)
317				toolCallTimerC = toolCallTimer.C
318				return
319			}
320			if !toolCallTimer.Stop() {
321				select {
322				case <-toolCallTimer.C:
323				default:
324				}
325			}
326			toolCallTimer.Reset(wd.toolCallTimeout)
327		}
328		stopToolCallTimer := func() {
329			if toolCallTimer == nil {
330				return
331			}
332			if !toolCallTimer.Stop() {
333				select {
334				case <-toolCallTimer.C:
335				default:
336				}
337			}
338			toolCallTimerC = nil
339		}
340	
341		// Arm the idle timer immediately so a session that never starts a tool
342		// call is still bounded.
343		if wd.idleTimeout > 0 {
344			idleTimer = time.NewTimer(wd.idleTimeout)
345			idleTimerC = idleTimer.C
346		}
347		defer func() {
348			if idleTimer != nil {
349				idleTimer.Stop()
350			}
351			if toolCallTimer != nil {
352				toolCallTimer.Stop()
353			}
354		}()
355	
356		for {
357			select {
358			case ev, ok := <-events:
359				if !ok {
360					return final, routing, progress
361				}
362				decoded, err := agentlib.DecodeServiceEvent(ev)
363				if err != nil {
364					continue
365				}
366				switch {
367				case decoded.ToolCall != nil:
368					// Meaningful: tool invocation starts. Reset idle, start per-call cap.
369					resetIdle()
370					startToolCallTimer()
371					callCopy := *decoded.ToolCall
372					pendingCall = &callCopy
373	
374				case decoded.ToolResult != nil:
375					// Meaningful: tool produced a result. Stop per-call timer.
376					stopToolCallTimer()
377					if pendingCall != nil {
378						key := makeLoopKey(*pendingCall, *decoded.ToolResult)
379						if ld.record(key) {
380							_, _ = fmt.Fprintf(os.Stderr, "agent: loop detected (command=%q repeated ≥4 times): cancelling\n", pendingCall.Name)
381							if wd.cancel != nil {
382								wd.cancel()
383							}
384							return final, routing, progress
385						}
386						pendingCall = nil
387					}
388					resetIdle()
389	
390				case decoded.Final != nil:
391					// Meaningful: execution complete. Stop all timers.
392					resetIdle()
393					stopToolCallTimer()
394					final = decoded.Final
395	
396				case decoded.RoutingDecision != nil:
397					// Not a meaningful progress event: routing is a one-time setup event.
398					routing = decoded.RoutingDecision
399					if w != nil {
400						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
401							_, _ = fmt.Fprint(w, line)
402						}
403					}
404	
405				case decoded.Progress != nil:
406					// Not meaningful for idle reset: progress events are emitted for
407					// any tool activity including tight loops that make no real change.
408					progress = append(progress, *decoded.Progress)
409					if w != nil {
410						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
411					}
412				}
413	
414			case <-idleTimerC:
415				_, _ = fmt.Fprintf(os.Stderr, "agent: idle timeout (%s without meaningful event): cancelling\n", wd.idleTimeout)
416				if wd.cancel != nil {
417					wd.cancel()
418				}
419				return final, routing, progress
420	
421			case <-toolCallTimerC:
422				name := ""
423				if pendingCall != nil {
424					name = pendingCall.Name
425				}
426				_, _ = fmt.Fprintf(os.Stderr, "agent: tool call timeout (%s, tool=%q): cancelling\n", wd.toolCallTimeout, name)
427				if wd.cancel != nil {
428					wd.cancel()
429				}
430				return final, routing, progress
431			}
432		}
433	}
434	
435	func selectedRoutingCandidateMetrics(routing *agentlib.ServiceRoutingDecisionData) (int, float64, float64, string) {
436		if routing == nil {
437			return 0, 0, 0, ""
438		}
439		for _, candidate := range routing.Candidates {
440			if candidate.Eligible && candidate.Model == routing.Model {
441				return candidate.Components.Power, candidate.Components.SpeedTPS, candidate.CostUSDPer1kTokens, candidate.CostSource
442			}
443		}
444		return 0, 0, 0, ""
445	}
